INSERT INTO `v1_dd1b48ff46423e2cca1e9fbf7adc0768c651db688c9012877bbc330482d02761` VALUES ("", "bgm_M199_juke", "2030/12/31 15:00:00", "お兄ちゃん争奪！\nどっちのチョコがおいしいでSHOW", "2020-02-15 15:00:00", 10000, "bgm_M199", "愛情たっぷりのチョコレートケー\nキを完成させよう！\n超キュートなタップゲーム！", 1002, "2030/12/31 15:00:00", 1001);
