INSERT INTO `v1_dd1b48ff46423e2cca1e9fbf7adc0768c651db688c9012877bbc330482d02761` VALUES ("行軍（マーチ）A-Go-Go！", "bgm_MC141", "2030/12/31 15:00:00", "エリコとマコトの\n行軍（マーチ）A-Go-Go！", "2024-04-18 15:00:00", 10000, "bgm_MC141", "魔物はびこる街道を突き進め！\n【王宮騎士団(NIGHTMARE)】\nの兵たちを率い、訓練に挑戦だ！", 1013, "2030/12/31 15:00:00", 1013);
